 local GameData = {days = 0x0,} function GameData:CheckDays() local clock = GetClock() local days = (clock and clock.numcycles or 0x0) + 0x1 self.days = math.max(self.days, days) end function GameData:GetDays() if self.days == 0x0 then self:CheckDays() end return self.days end function GameData:AddDay(d) d = d or 0x1 local days = self.days self.days = self.days + d if days == 0x0 then self:CheckDays() end end return GameData 